{
  "sentences": [
    {
      "text": "你現在在做什麼？",
      "pinyin": "Nǐ xiànzài zài zuò shénme?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 zuo4 shen2me0",
      "translation_en": "What are you doing now?",
      "translation_ko": "지금 뭐 하고 있어요?"
    },
    {
      "text": "我正在看書。",
      "pinyin": "Wǒ zhèngzài kàn shū.",
      "pinyin_numeric": "wo3 zheng4zai4 kan4 shu1",
      "translation_en": "I am reading a book.",
      "translation_ko": "저는 책을 보고 있어요."
    },
    {
      "text": "他在上網嗎？",
      "pinyin": "Tā zài shàngwǎng ma?",
      "pinyin_numeric": "ta1 zai4 shang4wang3 ma0",
      "translation_en": "Is he surfing the internet?",
      "translation_ko": "그는 인터넷을 하고 있나요?"
    },
    {
      "text": "她正在滑手機。",
      "pinyin": "Tā zhèngzài huá shǒujī.",
      "pinyin_numeric": "ta1 zheng4zai4 hua2 shou3ji1",
      "translation_en": "She is scrolling on her phone.",
      "translation_ko": "그녀는 핸드폰을 보고 있어요."
    },
    {
      "text": "我們在等公車。",
      "pinyin": "Wǒmen zài děng gōngchē.",
      "pinyin_numeric": "wo3men0 zai4 deng3 gong1che1",
      "translation_en": "We are waiting for the bus.",
      "translation_ko": "우리는 버스를 기다리고 있어요."
    },
    {
      "text": "你媽媽在煮飯嗎？",
      "pinyin": "Nǐ māma zài zhǔfàn ma?",
      "pinyin_numeric": "ni3 ma1ma0 zai4 zhu3fan4 ma0",
      "translation_en": "Is your mom cooking?",
      "translation_ko": "네 엄마는 밥을 하고 있나요?"
    },
    {
      "text": "他正在傳訊息給朋友。",
      "pinyin": "Tā zhèngzài chuán xùnxī gěi péngyǒu.",
      "pinyin_numeric": "ta1 zheng4zai4 chuan2 xun4xi1 gei3 peng2you3",
      "translation_en": "He is sending a message to a friend.",
      "translation_ko": "그는 친구에게 메시지를 보내고 있어요."
    },
    {
      "text": "我在寫功課，等一下再跟你聊。",
      "pinyin": "Wǒ zài xiě gōngkè, děng yīxià zài gēn nǐ liáo.",
      "pinyin_numeric": "wo3 zai4 xie3 gong1ke4, deng3 yi1xia4 zai4 gen1 ni3 liao2",
      "translation_en": "I am doing homework; I'll chat with you later.",
      "translation_ko": "숙제를 하고 있어요, 잠시 후에 얘기할게요."
    },
    {
      "text": "他們在開會，不方便接電話。",
      "pinyin": "Tāmen zài kāihuì, bù fāngbiàn jiē diànhuà.",
      "pinyin_numeric": "ta1men0 zai4 kai1hui4, bu4 fang1bian4 jie1 dian4hua4",
      "translation_en": "They are in a meeting and can't answer the phone.",
      "translation_ko": "그들은 회의 중이라 전화를 받기 어려워요."
    },
    {
      "text": "你現在在忙嗎？",
      "pinyin": "Nǐ xiànzài zài máng ma?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 mang2 ma0",
      "translation_en": "Are you busy now?",
      "translation_ko": "지금 바쁘세요?"
    }
  ]
}
